var e=JSON.parse(`[{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배! 괜찮아?!","JPN":"先輩！　大丈夫！？","ENG":"Shiyoon! You okay?!","TWN":"前輩！你還好嗎？"},"stage":{"bg":"PARK_DESTROYED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......그럭저럭 살아는 있는 것 같네요.","JPN":"……なんとか生きてはいるみたいです。","ENG":"Looks like I’m still breathing, more or less.","TWN":"……看樣子我還活著呢。"},"stage":{"bg":"PARK_DESTROYED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"제길, 저 녀석......!","JPN":"くそっ、あいつ……！","ENG":"Damn that scumbag...","TWN":"該死！那個傢伙……！"},"stage":{"bg":"PARK_DESTROYED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"지난번에 싸웠을 때보다 더 강해진 것 같아......!","JPN":"前回対戦した時よりも強くなったみたい……！","ENG":"It seems to have grown even stronger than last time!","TWN":"和上次相比好像變得更強了！"},"stage":{"bg":"PARK_DESTROYED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그야 지난번에는 알트 소대 분들과 스승님까지 한꺼번에 달려들었으니까요.","JPN":"そりゃあこの前は、アルト小隊や師匠もいましたからね。","ENG":"Well we did have the Master and the ALT Squad with us too back then.","TWN":"上次阿爾特小隊和師父們都一起上陣了……"},"stage":{"bg":"PARK_DESTROYED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"우리 둘만으로는 애먹는 게 당연하죠.","JPN":"僕たち二人だけじゃ、手を焼いて当然です。","ENG":"Of course we’ll struggle with just the two of us now.","TWN":"但現在卻只有我們兩個，當然會覺得難以對付。"},"stage":{"bg":"PARK_DESTROYED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"......흐음, 과연.","JPN":"……ふむ、なるほど。","ENG":"Hmm... I see.","TWN":"……嗯，原來如此。"},"stage":{"bg":"PARK_DESTROYED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"테라사이드 시스템의 서포트를 받는 나에게 이 정도의 데미지를 주다니.......","JPN":"テラサイドのサポートを受けている私に、これほどのダメージを与えるとは……","ENG":"If they could inflict this much damage on me even with the support of the Terraside system...","TWN":"得到特拉賽德系統支援的我，竟然會受到這種傷害……"},"stage":{"bg":"PARK_DESTROYED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"확실히 이전의 나이트로는 역부족이었을 것 같군.","JPN":"たしかに、以前のナイトでは力不足だっただろう。","ENG":"The previous version of the Knight wouldn’t have stood a chance indeed.","TWN":"以前的騎士力量的確不足。"},"stage":{"bg":"PARK_DESTROYED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......호오?","JPN":"……ほほう。","ENG":"Oh?","TWN":"……哦？"},"stage":{"bg":"PARK_DESTROYED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"너 이 자식! 대체 무슨 꿍꿍이야? 뭘 꾸미는 거지?!","JPN":"あんた、いったいどういうつもり？　何を企んでるの？","ENG":"Hey, stripper girl! What’s your deal this time? What are you plotting here?!","TWN":"妳這混蛋！妳在打什麼壞主意？妳又有什麼陰謀？！"},"stage":{"bg":"PARK_DESTROYED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PARK_DESTROYED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......아니. 대답할 필요 없어.","JPN":"……いや、答える必要なんてない。","ENG":"Never mind... Don't answer that.","TWN":"……不，沒必要回答我。"},"stage":{"bg":"PARK_DESTROYED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"더 이상 네놈들 속셈 따윈 궁금하지도 않아.","JPN":"もうあんたらの腹積もりなんかどうでもいい。","ENG":"I couldn’t care less about your evil schemes anymore.","TWN":"我對你們這些傢伙的陰謀毫無興趣。"},"stage":{"bg":"PARK_DESTROYED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"리플레이서라면 이제 지긋지긋해.","JPN":"リプレイサーなんて、もううんざり。","ENG":"I’m sick and tired of you Replacers.","TWN":"我已經對克隆集團感到厭煩了。"},"stage":{"bg":"PARK_DESTROYED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"차라리 잘됐어.","JPN":"現れてくれて良かった。","ENG":"It’s all for the best, really.","TWN":"這樣反而更好。"},"stage":{"bg":"PARK_DESTROYED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"네가 나타났다는 건 여기서 벌어진 일들도 모두 네놈들의 수작이라는 뜻이겠지.","JPN":"あんたが現れたということは、ここで起こったことも全部あんたらの仕業ということだろうから。","ENG":"If you’re here, that must mean that the Syndicate was behind everything that went down here.","TWN":"妳會出現在這裡，就代表這些事情是你們搞的鬼吧。"},"stage":{"bg":"PARK_DESTROYED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"미안해, 선배. 관할이나 규정 같은 어려운 건 잘 모르겠지만.......","JPN":"ごめんね、先輩。管轄やルールみたいな難しいことはよくわからないけど……","ENG":"Sorry, Shiyoon. I honestly don't get how all of this jurisdiction and regulation crap works...","TWN":"前輩，對不起。我不清楚這些複雜的管轄和規定……"},"stage":{"bg":"PARK_DESTROYED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"침식체도 아닌 리플레이서 놈들이 눈앞에 나타났는데 그냥 두고 볼 수가 없어.","JPN":"侵食体でもないリプレイサーのやつらを目前にして、放っておくわけにはいかないよ。","ENG":"I could turn a blind eye to C.O.'s for now, but I can’t just sit back and do nothing when there are Replacers in sight.","TWN":"但克隆集團這些不是侵蝕體的傢伙出現在我面前，我沒辦法眼睜睜地放過他們。"},"stage":{"bg":"PARK_DESTROYED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......미나 양.","JPN":"……ミナさん。","ENG":"Mina...","TWN":"……米娜小姐。"},"stage":{"bg":"PARK_DESTROYED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"덤벼! 이 개자식아!","JPN":"かかってこい！　このカス野郎！","ENG":"Come at me! You slutty scumbag!","TWN":"來啊！妳這個混蛋！"},"stage":{"bg":"PARK_DESTROYED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"박살내 주마!","JPN":"ぶっ潰してやる！","ENG":"I’ll crush you!","TWN":"看我打爆妳！"},"stage":{"bg":"PARK_DESTROYED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PARK_DESTROYED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"모체로부터 받은 정보와는 조금 다르군.","JPN":"母体からもらった情報とは少し異なるな。","ENG":"There appears to be a discrepancy from the information provided by the source body.","TWN":"和從母體得到的資訊有些不同呢。"},"stage":{"bg":"PARK_DESTROYED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"감정에 휘둘리긴 하지만, 이 정도로 공격적인 타입은 아닌 것처럼 보였는데.","JPN":"感情に振り回されることはあっても、これほど攻撃的なタイプではなさそうだったが。","ENG":"While the subject was said to be emotional, the data did not indicate this level of aggression.","TWN":"雖然她很容易被情緒控制，但應該不是這麼具有攻擊性的類型啊。"},"stage":{"bg":"PARK_DESTROYED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PARK_DESTROYED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"뭐, 상관없지.","JPN":"まあ、よい。","ENG":"No matter.","TWN":"算了，無所謂。"},"stage":{"bg":"PARK_DESTROYED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"나의 임무는 테라사이드 단말의 수호.","JPN":"私の任務はテラサイド端末の守護。","ENG":"My mission is to safeguard the Terraside Terminal.","TWN":"我的任務是要守護特拉賽德裝置。"},"stage":{"bg":"PARK_DESTROYED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"임무 수행을 위한 전투는 나의 본질과도 어긋나지 않는 일.","JPN":"任務遂行のための戦闘は、私の本質とも相反しないものだ。","ENG":"Engaging in combat for the mission is consistent with my fundamental nature.","TWN":"為執行任務而戰鬥，和我的本質並不矛盾。"},"stage":{"bg":"PARK_DESTROYED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"걸어오는 싸움이라면 마다할 이유가 없다.","JPN":"売られた喧嘩を買わない理由もない。","ENG":"There is no reason to decline a challenge to fight.","TWN":"沒有理由拒絕戰鬥。"},"stage":{"bg":"PARK_DESTROYED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"아니, 오히려 이쪽에서 부탁하고 싶을 정도군.","JPN":"いや、むしろこちらから買わせていただこう。","ENG":"If anything, this is something I would ask for first.","TWN":"不，我反而更希望這樣。"},"stage":{"bg":"PARK_DESTROYED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......뭘 중얼거리는 거야?!","JPN":"……何をぶつぶつ言ってんのよ！？","ENG":"What the heck are you mumbling about?!","TWN":"……妳在自言自語些什麼啊？"},"stage":{"bg":"PARK_DESTROYED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"올 생각이 없다면, 내가 먼저......!","JPN":"来る気がないなら、私が先に……！","ENG":"If you’re not going to come, I’ll go to you!","TWN":"……如果妳不上的話，那我就先……"},"stage":{"bg":"PARK_DESTROYED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_QM","text":{"KOREA":"그만둬라, 나이트.","JPN":"やめろ、ナイト。","ENG":"Stand down, Knight.","TWN":"住手，騎士。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK"},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......!!","JPN":"……！！","ENG":"......!!","TWN":"……！！"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_QM","text":{"KOREA":"네가 말했듯, 기사의 임무는 수호이지 격멸이 아니다.","JPN":"あなたが言ったように、騎士の任務は守護であって撃滅ではない。","ENG":"As you have said, the Knight’s mission is to safeguard, not to destroy.","TWN":"就像妳說的一樣，騎士的任務是守護特拉賽德裝置，而不是殲滅敵人。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"......너도 벌써 도착했나?","JPN":"……貴公も、もう着いたのか?","ENG":"You are already here too?","TWN":"……妳已經到啦？"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"흥이 깨지는군.","JPN":"興醒めだな。","ENG":"Talk about a wet blanket.","TWN":"真是掃興。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_QM","text":{"KOREA":"상대는 우리의 모체를 파괴했을 정도의 잠재력을 가진 존재.","JPN":"相手は我々の母体を破壊するほどの潜在力を持つ存在。","ENG":"The opponent possesses potential powerful enough to have destroyed our sources.","TWN":"對方有破壞我們母體的潛力。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_QM","text":{"KOREA":"그런 자들과 굳이 쓸데없는 싸움을 벌여 시스템의 에너지를 소모하는 것은......","JPN":"そんな相手と無駄な戦闘をして、システムのエネルギーを消耗するのは……","ENG":"Engaging in unnecessary combat with such adversaries would not only be a waste of the system’s energy...","TWN":"妳執意和那些人進行無意義的戰鬥，消耗系統的能量……"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_QM","text":{"KOREA":"우리의 목적을 완수하는 데 아무런 도움이 되지 않는다.","JPN":"我々の目的を達成するためには、不適切と判断する。","ENG":"But also does not aid in accomplishing our true objectives.","TWN":"對我們完成任務毫無幫助。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"저건.......","JPN":"あれは……","ENG":"Isn’t that...","TWN":"那個……"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......서, 설마?","JPN":"ま、まさか……","ENG":"N-no way...","TWN":"……難，難道是？"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"네 제안은 타당하다. 따라서 수락한다.","JPN":"貴公の提案は妥当だ。だから、受け入れよう。","ENG":"You present a valid point. I therefore accept.","TWN":"妳的建議合理。我接受。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"하지만, 이 말만은 해 둬야겠군.","JPN":"でも、これだけは言っておかねばなるまい。","ENG":"But let me make one thing clear.","TWN":"但也只是嘴上接受。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"애초에 우리 둘의 모체가 서로 사이가 좋았던 것 같지는 않지만......","JPN":"私の母体も仲は良くなかったようだが……","ENG":"Our sources did not seem to get along in the first place...","TWN":"本來我們兩個母體的關係就不太好……"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"나 또한 네가 그다지 좋아질 것 같지는 않다.","JPN":"今の私も、貴公のことをあまり好きになれそうにないな。","ENG":"And I don’t anticipate I will find you much more amiable either.","TWN":"我也不怎麼喜歡妳。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"비숍.","JPN":"ビショップ。","ENG":"Bishop.","TWN":"大主教。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"상관없다. 너도 그렇겠지?","JPN":"構わない。あなたもそうだと推測されるが？","ENG":"That does not bother me. I trust you feel likewise.","TWN":"無所謂，妳也這麼覺得吧？"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"물론.","JPN":"そのとおりだ。","ENG":"Of course.","TWN":"當然。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"나이트가 나타났길래 혹시나 했는데.......","JPN":"ナイトが現れた時点で、もしやとは思いましたが……","ENG":"I thought this might be the case when I saw the Knight...","TWN":"騎士都出現的話，那該不會……"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"역시.......","JPN":"案の定……","ENG":"But who knew I’d be right...","TWN":"果然……"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나, 나래?","JPN":"ナ、ナルミ？","ENG":"N-Narae?","TWN":"娜，娜拉？"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"죽지...... 않았던 거야?","JPN":"死んで……なかったの？","ENG":"She’s not... dead?","TWN":"妳沒死嗎？"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럴 리가.......","JPN":"そんなはずは……","ENG":"It can’t be...","TWN":"這……"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럴...... 리가...... 없는데......","JPN":"そんな……はずは……ないのに……","ENG":"That just... can’t be... true...","TWN":"怎麼可能……"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"정신 차려요, 미나 양! ","JPN":"しっかりしてください、ミナさん！","ENG":"Snap out of it, Mina! ","TWN":"振作一點，米娜小姐！"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"리플레이서 비숍의 사망은 미나 양이 직접 확인했잖아요?!","JPN":"リプレイサー・ビショップの死亡は、ミナさん自らが確認したじゃないですか！？","ENG":"You’ve seen the Replacer Bishop die yourself!","TWN":"妳不是親自看到克隆·大主教死了嗎？"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그녀가 살아있을 리가 없어요!","JPN":"彼女が生きているはずありません！","ENG":"There’s no way she'd still be alive!","TWN":"她不可能還活著！"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하, 하지만.......","JPN":"で、でも……","ENG":"B-but...","TWN":"可，可是……"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"왜 그러지, 비숍?","JPN":"どうした、ビショップ。","ENG":"What’s wrong, Bishop?","TWN":"怎麼了，大主教？"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"무언가 걸리는 것이라도 있나?","JPN":"何か引っかかることでもあるのか。","ENG":"Something on your mind?","TWN":"有什麼發現嗎？"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"아니, 아무것도 아니다.","JPN":"いや、問題ない。","ENG":"It’s nothing.","TWN":"沒有，什麼都沒有。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"그럼 즉시 이곳을 이탈하여 다음 테라사이드 단말의 설치 장소로 이동한다.","JPN":"それでは、直ちにここを離れて、次のテラサイド端末の設置場所へ移動しよう。","ENG":"I recommend we immediately depart for the next location for installing the Terraside Terminal.","TWN":"馬上離開這個地方，前往下一個特拉賽德裝置設置地。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"동의한다.","JPN":"同意する。","ENG":"Agreed.","TWN":"好。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};